import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

const API = process.env.REACT_APP_API_BASE;

export default function UploadBills() {
  const navigate = useNavigate();
  const empId = sessionStorage.getItem("empld");

  const [files, setFiles] = useState([]);
  const [bills, setBills] = useState([]);

  const loadBills = async () => {
    try {
      const res = await axios.get(`${API}/bills/${empId}`);
      setBills(res.data.bills || []);
    } catch (err) {
      console.log("FETCH BILLS ERROR:", err);
    }
  };

  useEffect(() => {
    loadBills();
  }, []);

  const uploadBills = async () => {
    if (!files.length) return alert("Select files first!");

    const formData = new FormData();
    for (let f of files) formData.append("files", f);
    formData.append("empId", empId);

    try {
      await axios.post(`${API}/bills/upload`, formData);
      alert("Bills uploaded successfully!");
      loadBills();
    } catch (err) {
      alert("Upload failed!");
    }
  };

  const deleteBill = async (id) => {
    if (!window.confirm("Delete this bill?")) return;

    try {
      await axios.delete(`${API}/bills/delete/${id}`);
      loadBills();
    } catch (err) {
      console.log("DELETE ERROR:", err);
    }
  };

  const downloadReport = () => {
    window.open(`${API}/bills/report/${empId}`, "_blank");
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        padding: "20px",
        background: "#eaf8f0",
        display: "flex",
        justifyContent: "center",
      }}
    >
      <div style={{ width: "92%", maxWidth: "900px" }}>
        {/* Back Button */}
        <button
          onClick={() => navigate(-1)}
          style={{
            background: "white",
            border: "1px solid #ddd",
            padding: "10px 14px",
            borderRadius: "10px",
            cursor: "pointer",
            fontSize: "18px",
            marginBottom: "10px",
          }}
        >
          ←
        </button>

        {/* Title */}
        <h2
          style={{
            color: "#0f9d58",
            fontWeight: "700",
            marginLeft: "8px",
            marginBottom: "15px",
          }}
        >
          Upload Bills
        </h2>

        {/* CARD — SAME SIZE AS TRAVEL/TICKET */}
        <div
          style={{
            background: "white",
            padding: "20px",
            borderRadius: "16px",
            boxShadow: "0px 3px 10px rgba(0,0,0,0.08)",
            marginBottom: "25px",
          }}
        >
          {/* Upload Row */}
          <div style={{ marginBottom: "20px" }}>
            <input
              type="file"
              multiple
              onChange={(e) => setFiles(e.target.files)}
              style={{
                padding: "10px",
                borderRadius: "10px",
                border: "1px solid #ccc",
                width: "70%",
              }}
            />

            <button
              onClick={uploadBills}
              style={{
                marginLeft: "12px",
                background: "#0f9d58",
                color: "white",
                padding: "12px 20px",
                borderRadius: "10px",
                border: "none",
                cursor: "pointer",
                fontWeight: "600",
              }}
            >
              Upload Bills
            </button>
          </div>

          {/* TABLE */}
          <table
            style={{
              width: "100%",
              borderCollapse: "collapse",
              textAlign: "left",
            }}
          >
            <thead>
              <tr style={{ background: "#eaf8f0" }}>
                <th style={th}>Date</th>
                <th style={th}>File Name</th>
                <th style={th}>Preview</th>
                <th style={th}>Delete</th>
              </tr>
            </thead>

            <tbody>
              {bills.length === 0 ? (
                <tr>
                  <td colSpan="4" style={noData}>No bills uploaded</td>
                </tr>
              ) : (
                bills.map((b) => (
                  <tr key={b.id}>
                    <td style={td}>
                      {new Date(b.uploaded_at).toLocaleDateString()}
                    </td>
                    <td style={td}>{b.file_name}</td>
                    <td style={td}>
                      <a
                        href={b.file_path}
                        target="_blank"
                        rel="noopener noreferrer"
                        style={{ color: "#0f9d58", fontWeight: "600" }}
                      >
                        View
                      </a>
                    </td>
                    <td style={td}>
                      <button
                        onClick={() => deleteBill(b.id)}
                        style={deleteBtn}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* DOWNLOAD REPORT BUTTON */}
        <button onClick={downloadReport} style={downloadBtn}>
          📄 Download Monthly Bills Report
        </button>
      </div>
    </div>
  );
}

const th = {
  padding: "12px",
  fontWeight: "700",
  fontSize: "15px",
};

const td = {
  padding: "12px",
  borderBottom: "1px solid #eee",
  fontSize: "15px",
};

const noData = {
  padding: "20px",
  textAlign: "center",
  color: "#777",
  fontSize: "16px",
};

const deleteBtn = {
  background: "#e53935",
  padding: "6px 12px",
  borderRadius: "8px",
  color: "white",
  border: "none",
  cursor: "pointer",
};

const downloadBtn = {
  background: "#0f9d58",
  padding: "14px 20px",
  borderRadius: "10px",
  color: "white",
  border: "none",
  marginTop: "5px",
  fontWeight: "600",
  cursor: "pointer",
};
